package com.enterprise.auth.repository;

import com.enterprise.auth.entity.BackupCode;
import com.enterprise.auth.entity.User;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

import java.util.List;

@Repository
public interface BackupCodeRepository extends JpaRepository<BackupCode, Long> {
    List<BackupCode> findByUserAndUsedFalse(User user);
    List<BackupCode> findByUser(User user);
    void deleteByUser(User user);

    @Query("SELECT COUNT(b) FROM BackupCode b WHERE b.user = :user AND b.used = false")
    long countUnusedByUser(@Param("user") User user);
}

